// ============================================================
// Process Results + Format Telegram Message
//
// Runs once after the Done branch of Loop Over Items.
// Reads all accumulated funding rate data from global staticData,
// splits into critical / warning tiers, builds an HTML message
// for Telegram, and resets the accumulator for the next run.
// ============================================================

// --- Thresholds (must match Accumulate node) ---
const WARNING_THRESHOLD  = 0.0010;
const CRITICAL_THRESHOLD = 0.0020;

// --- Read and reset accumulator ---
const sd = $getWorkflowStaticData('global');
const allResults = Array.isArray(sd.fr_results) ? [...sd.fr_results] : [];
sd.fr_results = [];

// --- Classify ---
const criticals = allResults
  .filter(r => r.level === 'critical')
  .sort((a, b) => b.absFR - a.absFR);

const warnings = allResults
  .filter(r => r.level === 'warning')
  .sort((a, b) => b.absFR - a.absFR);

const alertCount = criticals.length + warnings.length;

if (alertCount === 0) {
  return [{ json: { hasAlerts: false, message: '' } }];
}

// --- Format ---
const timestamp = new Date().toLocaleString('en-GB', {
  timeZone: 'Asia/Ho_Chi_Minh',
  day: '2-digit', month: '2-digit', year: 'numeric',
  hour: '2-digit', minute: '2-digit', second: '2-digit',
  hour12: false
});

function formatCoin(r) {
  const icon = r.level === 'critical' ? '🔴' : '🟡';
  const sign = r.fundingRate >= 0 ? '+' : '';
  const dir  = r.fundingRate >= 0
    ? '🟢 Longs pay Shorts'
    : '🔴 Shorts pay Longs';
  return `${icon} <b>${r.symbol}</b>: <code>${sign}${r.frPercent}%</code>
    ${dir} | next in ${r.hoursLeft}h`;
}

const lines = [];
lines.push(`📡 <b>Funding Rate Monitor</b>`);
lines.push(`🕐 ${timestamp} (ICT)`);
lines.push(`📊 Scanned: top ${allResults.length} USDT perps by 24h volume`);
lines.push(``);

if (criticals.length > 0) {
  lines.push(`🔴 <b>CRITICAL (≥${(CRITICAL_THRESHOLD * 100).toFixed(2)}%)</b> — ${criticals.length} coin${criticals.length > 1 ? 's' : ''}`);
  lines.push(`${'─'.repeat(28)}`);
  criticals.forEach(r => lines.push(formatCoin(r)));
  lines.push(``);
}

if (warnings.length > 0) {
  lines.push(`🟡 <b>WARNING (≥${(WARNING_THRESHOLD * 100).toFixed(2)}%)</b> — ${warnings.length} coin${warnings.length > 1 ? 's' : ''}`);
  lines.push(`${'─'.repeat(28)}`);
  warnings.forEach(r => lines.push(formatCoin(r)));
}

return [{
  json: {
    hasAlerts: true,
    alertCount,
    message: lines.join('\n'),
  }
}];

// ============================================================
// Accumulate Funding Rate Data
//
// Runs inside the loop body. Parses the premiumIndex response,
// classifies the funding rate level (normal / warning / critical),
// and pushes the result into the global staticData accumulator.
// Output connects back to Loop Over Items for the next iteration.
// ============================================================

// --- Thresholds (adjust to taste) ---
const WARNING_THRESHOLD  = 0.0010; // 0.10%
const CRITICAL_THRESHOLD = 0.0020; // 0.20%

// --- Accumulator guard ---
const sd = $getWorkflowStaticData('global');
if (!Array.isArray(sd.fr_results)) sd.fr_results = [];

const raw = $input.first().json;

// Skip on request error (delisted symbol, timeout, etc.)
if (!raw || !raw.symbol) {
  return [{ json: { skipped: true } }];
}

const symbol      = raw.symbol;
const fundingRate = parseFloat(raw.lastFundingRate);
const absFR       = Math.abs(fundingRate);
const frPercent   = (fundingRate * 100).toFixed(4);
const markPrice   = parseFloat(raw.markPrice);
const nextMs      = parseInt(raw.nextFundingTime);
const hoursLeft   = ((nextMs - Date.now()) / 3600000).toFixed(1);

// FR > 0: longs pay shorts (bullish crowding)
// FR < 0: shorts pay longs (bearish crowding)
const direction = fundingRate >= 0
  ? 'Longs pay Shorts'
  : 'Shorts pay Longs';

let level = 'normal';
if (absFR >= CRITICAL_THRESHOLD)     level = 'critical';
else if (absFR >= WARNING_THRESHOLD) level = 'warning';

sd.fr_results.push({
  symbol, fundingRate, frPercent, absFR,
  markPrice, hoursLeft, direction, level
});

return [{ json: { symbol, level } }];

// ============================================================
// Sort & Select Top N by 24h Volume
//
// Filters USDT perpetual pairs, excludes stablecoins and fiat
// pairs, sorts by 24h quote volume descending, and returns
// the top N symbols. Resets the global staticData accumulator
// before the loop begins.
// ============================================================

// --- Configuration ---
const TOP_N = 20;

const BLACKLIST_SYMBOLS = new Set([
  'USDCUSDT','BUSDUSDT','TUSDUSDT','USDPUSDT','FDUSDUSDT',
  'DAIUSDT','USDDUSDT','FRAXUSDT','LUSDUSDT','GUSDUSDT',
  'SUSDUSDT','USTCUSDT','EURUSDT','EUROCUSDT','EURSUSDT',
  'AGEURUSDT','GBPTUSDT','JPYCUSDT','CNHTUSDT','XSGDUSDT',
  'NZDSUSDT','CADCUSDT','TRYBUSDT','BRLAUSDT','IDRTUSDT','BIDRUSDT',
]);

const FIAT_PATTERNS = [
  'USD','EUR','JPY','GBP','AUD','CAD','CHF','CNY','CNH','KRW',
  'TRY','BRL','IDR','SGD','NZD','HKD','SEK','NOK','DKK','PLN',
  'CZK','MXN','ZAR','THB','PHP','INR','RUB',
];

// --- Filter ---
const tickers = $input.all().map(item => item.json);

const filtered = tickers.filter(t => {
  const sym = t.symbol;

  // Keep only USDT perpetual pairs
  if (!sym.endsWith('USDT')) return false;

  // Exclude known stablecoins and fiat tokens
  if (BLACKLIST_SYMBOLS.has(sym)) return false;

  // Exclude fiat-pair patterns (e.g. EURUSDT, GBPUSDT)
  const base = sym.slice(0, -4);
  if (FIAT_PATTERNS.some(fiat =>
    base === fiat || base.startsWith(fiat) || base.endsWith(fiat)
  )) {
    return false;
  }

  return true;
});

// --- Sort by 24h quote volume (USDT) descending ---
filtered.sort((a, b) =>
  parseFloat(b.quoteVolume) - parseFloat(a.quoteVolume)
);

const topN = filtered.slice(0, TOP_N);

// --- Reset accumulator before loop starts ---
const sd = $getWorkflowStaticData('global');
sd.fr_results = [];

return topN.map(t => ({
  json: {
    symbol: t.symbol,
    quoteVolume: parseFloat(t.quoteVolume),
    priceChangePercent: parseFloat(t.priceChangePercent),
    lastPrice: parseFloat(t.lastPrice)
  }
}));
